function isValidAnchorTag(s) {
  var rels = s.match(/rel=['"](.*?)['"]/g);
  var validRelValues = new Set(['noopener', 'noreferrer', 'external', 'nofollow', 'noopener noreferrer', 'noreferrer noopener', 'external nofollow']);
  for (var i = 0; i < rels.length; i++) {
    var value = rels[i].split('=')[1].trim();
    if (!validRelValues.has(value)) return false;
  }
  return true;
}

