class Solution:
  def is_valid_anchor_tag(self, s: str) -> bool:
    import re
    rels = re.findall(r'rel=['"](.*?)['"]', s)
    valid_rel_values = {'noopener', 'noreferrer', 'external', 'nofollow', 'noopener noreferrer', 'noreferrer noopener', 'external nofollow'}
    for value in rels:
      value = value.strip()
      if value not in valid_rel_values:
        return False
    return True
